import React, { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import PostCard from '../components/PostCard';
import { fetchFeed, fetchAllPosts, createPost } from '../utils/api';
import './Feed.css';

const Feed = () => {
  const { user } = useAuth();
  const [posts, setPosts] = useState([]);
  const [content, setContent] = useState('');
  const [loading, setLoading] = useState(true);
  const [posting, setPosting] = useState(false);
  const [error, setError] = useState('');
  const [tab, setTab] = useState('feed');

  const loadPosts = async () => {
    setLoading(true);
    try {
      const { data } = tab === 'feed' ? await fetchFeed() : await fetchAllPosts();
      setPosts(data.posts);
    } catch {
      setError('Failed to load posts.');
    }
    setLoading(false);
  };

  useEffect(() => { loadPosts(); }, [tab]);

  const handlePost = async (e) => {
    e.preventDefault();
    if (!content.trim()) return;
    setPosting(true); setError('');
    try {
      const { data } = await createPost(content);
      setPosts((prev) => [data.post, ...prev]);
      setContent('');
    } catch (err) {
      setError(err.response?.data?.message || 'Failed to create post.');
    }
    setPosting(false);
  };

  const handleDelete = (id) => setPosts((prev) => prev.filter((p) => p._id !== id));

  return (
    <main className="feed-layout">
      <div className="feed-main">
        <div className="card composer">
          <div className="composer-header">
            <div className="avatar avatar-md">{user?.username?.[0]?.toUpperCase()}</div>
            <textarea className="input composer-input" placeholder={`What's on your mind, ${user?.username}?`} value={content} onChange={(e) => setContent(e.target.value)} maxLength={500} rows={3} />
          </div>
          {error && <div className="alert alert-error">{error}</div>}
          <div className="composer-footer">
            <span className={`char-count ${content.length > 450 ? 'warn' : ''}`}>{content.length}/500</span>
            <button className="btn btn-primary" onClick={handlePost} disabled={posting || !content.trim()}>
              {posting ? 'Posting…' : 'Post'}
            </button>
          </div>
        </div>

        <div className="feed-tabs">
          <button className={`feed-tab ${tab === 'feed' ? 'active' : ''}`} onClick={() => setTab('feed')}>Following</button>
          <button className={`feed-tab ${tab === 'explore' ? 'active' : ''}`} onClick={() => setTab('explore')}>Explore</button>
        </div>

        {loading ? (
          <div className="spinner" />
        ) : posts.length === 0 ? (
          <div className="empty-state card">
            <div className="empty-icon">👋</div>
            <h3>{tab === 'feed' ? 'Your feed is empty' : 'No posts yet'}</h3>
            <p className="text-muted text-sm">{tab === 'feed' ? 'Follow users or switch to Explore.' : 'Be the first to post!'}</p>
          </div>
        ) : (
          posts.map((post) => <PostCard key={post._id} post={post} onDelete={handleDelete} />)
        )}
      </div>

      <aside className="feed-sidebar">
        <div className="card sidebar-profile">
          <div className="avatar avatar-md">{user?.username?.[0]?.toUpperCase()}</div>
          <div>
            <div style={{ fontWeight: 700 }}>@{user?.username}</div>
            <div className="text-muted text-sm">{user?.bio || 'No bio yet'}</div>
          </div>
        </div>
        <div className="card sidebar-tip">
          <h3 style={{ marginBottom: '0.5rem', fontSize: '0.9rem' }}>💡 Tips</h3>
          <ul className="tip-list text-sm text-muted">
            <li>Search for users using the top bar</li>
            <li>Follow users to see their posts</li>
            <li>Click ♥ to like a post</li>
            <li>Click the bubble to comment</li>
          </ul>
        </div>
      </aside>
    </main>
  );
};

export default Feed;
